.darma-loader-darma-custom-649__spinner {color: var(--loader-color, #a855f7);

  width: 3em;
  height: 3em;
  cursor: not-allowed;
  border-radius: 50%;
  border: 2px solid #444;
  box-shadow: -10px -10px 10px #6359f8, 0px -10px 10px 0px #9c32e2, 10px -10px 10px #f36896, 10px 0 10px #ff0b0b, 10px 10px 10px 0px #ff5500, 0 10px 10px 0px #ff9500, -10px 10px 10px 0px #ffb700;
  animation: darma-loader-darma-custom-649-rot55 0.7s linear infinite;
}

.darma-loader-darma-custom-649__spinnerin {
  border: 2px solid #444;
  width: 1.5em;
  height: 1.5em;
  border-radius: 50%;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

@keyframes darma-loader-darma-custom-649-rot55 {
  to {
    transform: rotate(360deg);
  }
}

